SELECT DISTINCT
	-- INFO RESTRICCION
	a.id_asu ID_Restriccion,
	a.ASu_TipoGenerico Tipo,
	a.ASu_TipoSuplemento Categoria,
	i.IAS_Nombre Nombre,
	a.ASu_Activo Activo,
	a.asu_grupocontrolacceso,

	-- INFO ACCESO
	ca.Id_CAc,
	cae.Id_CAE,
	CASE cae.CAE_denegar 
			WHEN 0 THEN 'Permitido'
			ELSE 'Denegado' 
		END Acceso,

	mer.Mer_Nombre Mercado,
	cae.Id_GPa GrupoPaises,
	grp.GPa_Nombre GrupoPaises,
	cae.Id_Pai Pais,
	pai.pai_Nombre Pais,
	ca.id_gra GrupoAgencia,
	gra.GRA_Nombre GrupoAgencia,
	ca.Id_Cli Agencia,
	cli.cli_Nombre Agencia
FROM 
				Tbl_alojamientosuplemento			a																			--> Información Restricción
	LEFT JOIN	Tbl_IdiNASu							i		ON i.id_asu = a.id_asu AND i.Id_Idi = 'ES'							--> Nombre Restricción                           
	LEFT JOIN	Tbl_ControlAcceso					ca		ON ca.CAc_Codigo = a.asu_grupocontrolacceso AND ca.CAc_Tipo='GrAc'	--> Condiciones de Acceso
    LEFT JOIN	Tbl_ControlAccesoExtendido			cae		ON ca.Id_CAc = cae.Id_CAc     
	LEFT JOIN	Tbl_Mercado							mer		ON mer.Id_Mer = ca.Id_Mer
	LEFT JOIN	Tbl_GrupoPais						grp		ON grp.id_GPa = cae.Id_GPa
	LEFT JOIN	Tbl_Paises							pai		ON pai.id_pai = cae.Id_Pai
	LEFT JOIN	Tbl_GrupoAgencia					gra		ON gra.Id_GRA = ca.Id_Gra
	LEFT JOIN	Tbl_Cliente							cli		ON cli.Id_Cli = ca.Id_Cli
WHERE 
	1 = 1
	AND a.ASu_TipoGenerico = 'Restriccion'																						--> Tipo Restricción (otros: Suplemento, Descuento,...)
	AND a.ASu_TipoSuplemento = 'Basico'
	AND a.Id_ASu IN (40840820,41063161,41302951,42395085,43331971,44686199,44770875,45752152,46395523,47930914,48049857,48261001,48479878,48489506,48578238,48686285,48762721,49146743,49296475,49314680,49572557,52810368,53075897,53234170,53719512,54389729,55567973,56288423,56794892,60261368,62186259,62350543,62603150,62648059,64094443,64382140,64384932,64658812,65053739,65063765,65118297,65118907,65233328,65267534,65281139,65396717,65635674,65881929,65949439,66318788,66384688,66506841,66513985,67008279,67100756,67933182,68124658,68286019,68306930,68441096,68545810,68927323,69284236,70456939,71136500,71606670,72486582,73214411,75083195,75742193,76404577,76617741,76743532,77460087,78104132,78673901,78694600,79762640,79963834,80503601,82186545,82413457,82460143,82956641,83628512,83638921,84511253,84511315,84612352,84915718,86171358,86472161,86547165,86548593,86549035,86590608,87169839,87171015,87358310,87853291,87930781,88388000,88418575,88844100,89022698,89226071,89366558,89370813,89833300,89898456,90257231,90532449,91031613,91046348,91707032,91708414,91709696,92313922,92402183,92705853,93340779,93705841,94062553,94382168,94942800,94983636,95513772,95631389,96560707,96794948,97066475,97464630,99073954,99103919,99488598,99488662,99491512,99491985,99540624,99647787,99648916,100146719,100266494,101234526,101460001,101545639,101573339,101655977,102173659,102173904,102173905,102224350,102270869,102282221,102338178,102571773,102571926,102572095,102885570,103189071,103200506,103436122,103768745,104526786,104545576,104570060,104854054,104854966,105067434,105365984,105413653,105470790,105544288,105829252,106660648,107106845,107149151,107177915,107197661,107238251,107241322,107242890,107244812,107246122,107364777,108338458,108384718,108384762,108385356,108401839,108482205,108546210,108551386,108551424,108556626,108558909,108559701,108560367,108560829,108644386,109092865,109093481,109121950,109261885,109383687,109384563,109721450,109722049,109735369,109745259,109916382,109950615,110